INSERT INTO public.procurement_line_years (line_id, fiscal_year, service, appropriation, appr_code, ba, line_number, title, quantity, unit_cost, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$PROC_ARMY_NA_L0028$$, 2027, $$Army$$, $$PROC_ARMY$$, $$ARMY$$, NULL, $$28$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$ set may not be exact or sum exactly due to rounding.

Justification:
FY 2027 Procurement funding supports the Common Missile Warning System (CMWS) and the Limited Interim Missile Warning System (LIMWS).

For CMWS, this includes software maintenance, system engineering, system of systems analysis, algorithm analysis, and System Test and Evaluation (ST&E) to ensure it continues to meet operational
requirements.

For the LIMWS Quick Reaction Capability (QRC), the funding supports direct combat support expenses in the Central Command (CENTCOM) Area of Responsibility (AOR) through software sustainment,
contractor logistics, and product support. Request to Army Futures Command to assign a disposition official for LIMWS was requested on 31 March 2025 as outlined in AR 71-9 and the program is awaiting
decision.

FY 2026 to FY 2027 funding decrease is due to reduced LIMWS Sustainment Support.

Additionally, CMWS/LIMWS supports rotational based capability for Army Aviation.




